mapper.sql:
SELECT U.user_seq, U.user_id, U.user_nm, U.mobile_no, U.dept_nm, U.tel_no, U.email, U.reg_dt, UT.user_type_seq, UT.user_type, UT.org_code, UT.org_nm, UT.org_type, UT.dept_code, ISNULL(UT.approval_yn, 'Y') AS approval_yn, UT.approval_user_nm, UT.approval_dt, RM.role_code, S.sys_id, S.sys_nm FROM TB_USER_INFO U LEFT JOIN TB_USER_TYPE_INFO UT ON U.user_id = UT.user_id LEFT JOIN TB_USER_ROLE_MAP RM ON U.user_id = RM.user_id LEFT JOIN TB_SYS_INFO S ON UT.org_code = S.org_code WHERE 1 = 1
AND S.sys_id = #{sysId}
AND ISNULL(UT.approval_yn, 'Y') = #{approvalYn}
AND UT.user_type = #{userType}
AND (U.user_nm LIKE CONCAT('%', #{keyword}, '%') OR U.user_id LIKE CONCAT('%', #{keyword}, '%') OR S.sys_nm LIKE CONCAT('%', #{keyword}, '%'))

mapper.select:
SELECT PL.*
FROM (
    SELECT PO.*, ROW_NUMBER() OVER(ORDER BY user_seq DESC) AS rsn
    FROM (  ) PO
) PL
WHERE rsn > #{minSn} AND rsn <= #{maxSn}

