mapper.update:
UPDATE TB_USER_INFO SET
    user_nm   = #{userNm},
    dept_nm   = #{deptNm},
    email     = #{email},
    mobile_no = #{mobileNo},
    tel_no    = #{telNo}

        , user_pwd = #{userPwd}

